var monthCategories = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
 
/* Year-wise data. Each year: Jan-Jun populated, rest 0 (swap this
   object for a real API response keyed by year when ready). */
var yearlyData = {
  2026: {
    energy: [2,  9,  9,  17, 4,  4,  0,0,0,0,0,0],
    water:  [10, 28, 28, 62, 15, 13, 0,0,0,0,0,0],
    motor:  [3,  11, 9,  21, 5,  5,  0,0,0,0,0,0]
  },
  2025: {
    energy: [1,  6,  8,  14, 5,  3,  2, 1, 0, 0, 0, 0],
    water:  [7,  22, 24, 50, 12, 10, 6, 3, 0, 0, 0, 0],
    motor:  [2,  8,  7,  17, 4,  4,  2, 1, 0, 0, 0, 0]
  },
  2024: {
    energy: [3,  7,  6,  12, 6,  5,  4, 3, 2, 1, 0, 0],
    water:  [12, 25, 20, 45, 18, 15, 9, 6, 3, 1, 0, 0],
    motor:  [4,  9,  6,  15, 6,  5,  3, 2, 1, 0, 0, 0]
  }
};
 
var currentYear = 2026;
var energyData = yearlyData[currentYear].energy;
var waterData   = yearlyData[currentYear].water;
var motorData   = yearlyData[currentYear].motor;
 
var options = {
  chart:{
    type:"bar",
    height:400,
    toolbar:{ show:false }
  },
  series:[
    { name:"Total Harvested Energy (kWh)", data: energyData },
    { name:"Total Water Output (kL)",      data: waterData  },
    { name:"Motor Runs Hours",             data: motorData  }
  ],
  colors:["#e0e3ea","#8fcaf8","#516cdd"],
  plotOptions:{
    bar:{ columnWidth:"55%", endingShape:"rounded", borderRadius:2 }
  },
  dataLabels:{ enabled:false },
  stroke:{ show:false },
  grid:{
    borderColor:"#eef0f3",
    xaxis:{ lines:{ show:false } },
    yaxis:{ lines:{ show:true } }
  },
  xaxis:{
    categories: monthCategories,
    title:{ text:"Months", style:{ fontSize:"12px", color:"#8a94a6" } },
    axisBorder:{ show:false },
    axisTicks:{ show:false },
    labels:{ style:{ fontSize:"12px", colors:"#8a94a6" } }
  },
  yaxis:{
    min:0,
    labels:{ style:{ fontSize:"12px", colors:"#8a94a6" } }
  },
  legend:{
    show:true,
    position:"top",
    horizontalAlign:"left",
    fontSize:"13.5px",
    fontFamily:"Segoe UI",
    labels:{ colors:"#374151" },
    markers:{ width:12, height:12, radius:12 },
    itemMargin:{ horizontal:20, vertical:10 }
  },
  tooltip:{
    shared:true,
    intersect:false
  }
};
 
var chart = new ApexCharts(document.querySelector("#totalizer-chart"), options);
chart.render();
 
function updateChartForYear(year){
  var d = yearlyData[year] || yearlyData[2026];
  energyData = d.energy;
  waterData  = d.water;
  motorData  = d.motor;
  chart.updateSeries([
    { data: energyData },
    { data: waterData },
    { data: motorData }
  ]);
}
 
/* ---------------------------------------------------------
   Bootstrap-datepicker wired as a year-only picker
---------------------------------------------------------- */
$(function(){
  $('#yearSelect').datepicker({
    format: 'yyyy',
    minViewMode: 'years',
    startView: 'years',
    autoclose: true,
    todayHighlight: true,
    orientation: 'bottom auto'
  }).on('changeDate', function(e){
    var year = e.date.getFullYear();
    $('#yearSelect').val(year);
    currentYear = year;
    updateChartForYear(year);
  });
});
 
document.getElementById("refreshBtn").addEventListener("click", function(){
  updateChartForYear(currentYear);
});